            <Route path="/learning" element={<Learning />} />
            <Route path="/projects" element={<ProjectsResearch />} />
            <Route path="/partner" element={<Partner />} />
            <Route path="/get-started" element={<GetStarted />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </HashRouter>
  );
};

export default App;

