import React, { useState } from 'react';

interface SurveyWidgetProps {
  isOpen: boolean;
  onClose: () => void;
  onToggle: () => void;
}

const SurveyWidget: React.FC<SurveyWidgetProps> = ({ isOpen, onClose, onToggle }) => {
  const [step, setStep] = useState(0);
  const [role, setRole] = useState('');

  const handleReset = () => {
    setStep(0);
    setRole('');
    onClose();
  };

  if (!isOpen) {
    return (
      <div className="fixed top-24 right-4 z-40 animate-bounce">
        <button
          onClick={onToggle}
          className="bg-orange-600 text-white px-4 py-3 font-bold uppercase text-[10px] tracking-widest shadow-[4px_4px_0px_0px_rgba(15,23,42,1)] hover:bg-slate-900 transition-all flex items-center gap-2"
        >
          <span className="text-lg">📋</span>
          <span>Quick Survey</span>
        </button>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center px-4 bg-slate-900/40 backdrop-blur-sm">
      <div className="bg-white border-2 border-slate-900 max-w-lg w-full p-8 relative shadow-[12px_12px_0px_0px_rgba(234,88,12,1)]">
        <button 
          onClick={handleReset}
          className="absolute top-4 right-4 text-slate-400 hover:text-slate-900 font-bold text-xl"
        >
          &times;
        </button>

        <div className="absolute top-0 left-0 w-16 h-1 bg-orange-600"></div>

        {step === 0 && (
          <div className="space-y-8 py-4">
            <div className="space-y-2">
              <span className="text-orange-600 font-bold text-[10px] uppercase tracking-[0.3em]">Navigator</span>
              <h2 className="text-2xl font-bold text-slate-900 uppercase tracking-tighter italic">Where do you stand?</h2>
              <p className="text-slate-500 text-sm font-medium">We'll help you navigate the DGA ecosystem.</p>
            </div>

            <div className="grid grid-cols-1 gap-3">
              {[
                { id: 'learn', label: 'The Student', sub: 'I want to learn the fundamentals.', icon: '📚' },
                { id: 'research', label: 'The Researcher', sub: 'I want to contribute evidence.', icon: '🔬' },
                { id: 'build', label: 'The Builder', sub: 'I want to build tools.', icon: '🛠️' }
              ].map((opt) => (
                <button
                  key={opt.id}
                  onClick={() => { setRole(opt.id); setStep(1); }}
                  className="flex items-center p-4 border-2 border-slate-100 hover:border-orange-600 hover:bg-orange-50 transition-all text-left group"
                >
                  <span className="text-3xl mr-4 group-hover:scale-110 transition-transform">{opt.icon}</span>
                  <div>
                    <p className="font-bold text-slate-900 uppercase text-[11px] tracking-widest">{opt.label}</p>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{opt.sub}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {step === 1 && (
          <div className="space-y-6 py-4">
            <h2 className="text-2xl font-bold text-slate-900 uppercase tracking-tighter">Recommended Pathway:</h2>
            <div className="space-y-4">
              {role === 'learn' && (
                <div className="p-4 bg-orange-50 border-l-4 border-orange-600">
                  <p className="font-bold text-slate-900 text-xs uppercase tracking-widest mb-1">1-Hour Intro & Diploma</p>
                  <p className="text-[11px] text-slate-600 font-medium">Begin with the foundational awareness syllabus.</p>
                </div>
              )}
              {role === 'research' && (
                <div className="p-4 bg-slate-50 border-l-4 border-slate-900">
                  <p className="font-bold text-slate-900 text-xs uppercase tracking-widest mb-1">MedSchlr Onboarding</p>
                  <p className="text-[11px] text-slate-600 font-medium">Join the decentralized knowledge commons.</p>
                </div>
              )}
              {role === 'build' && (
                <div className="p-4 bg-orange-50 border-l-4 border-slate-900">
                  <p className="font-bold text-slate-900 text-xs uppercase tracking-widest mb-1">BHN Contributor</p>
                  <p className="text-[11px] text-slate-600 font-medium">Help build the Bitcoin Health Network directory.</p>
                </div>
              )}
            </div>
            <div className="flex flex-col gap-3 pt-4">
              <button 
                onClick={handleReset}
                className="bg-slate-900 text-white font-bold py-4 uppercase text-[10px] tracking-[0.3em] hover:bg-orange-600 transition-all"
              >
                Go to {role} Section
              </button>
              <button 
                onClick={() => setStep(0)}
                className="text-[10px] font-bold uppercase tracking-widest text-slate-400 hover:text-slate-900 transition-colors"
              >
                Back to start
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
