            <div className="p-10 border-2 border-slate-900 bg-slate-50 text-left">
              <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-orange-600 mb-2">Recommended Step:</p>
              {track === 'learn' ? (
                <p className="text-slate-900 font-bold uppercase text-lg italic tracking-tight leading-tight">
                  {timeCommitment === '< 1 Hr (Intro)' ? 'The 1-Hour Orientation' : 'The 10-Week Professional Diploma'}
                </p>
              ) : (
                <p className="text-slate-900 font-bold uppercase text-lg italic tracking-tight leading-tight">
                  {skills.includes('Development') ? 'Practice Lab Contributor' : 'Research Studio Associate'}
                </p>
              )}
            </div>

            <div className="flex flex-col gap-3">
              <button 
                onClick={() => handleFinish(track === 'learn' ? '/learning' : '/projects')}
                className="bg-slate-900 text-white font-bold py-5 uppercase text-[11px] tracking-[0.3em] hover:bg-orange-600 transition-all shadow-[8px_8px_0px_0px_rgba(234,88,12,0.4)]"
              >
                Enter {track === 'learn' ? 'Learning' : 'Studio'}
              </button>
              <button onClick={() => setStep(0)} className="text-[10px] font-bold uppercase tracking-widest text-slate-400 hover:text-slate-900 transition-colors py-2 italic underline underline-offset-4">Change selection</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SurveyWidget;
